    public static bool TryGetPath(int playerId, out string webPath)
    {
        return PhotoByPlayerId.TryGetValue(playerId, out webPath!);
    }

    public static bool TryGetPath(string? fullName, string? teamName, out string webPath)
    {
        var playerKey = NormalizeKey(fullName);
        if (string.IsNullOrWhiteSpace(playerKey))
        {
            webPath = string.Empty;
            return false;
        }

        var teamKey = NormalizeKey(teamName);
        if (!string.IsNullOrWhiteSpace(teamKey)
            && PhotoByIdentity.TryGetValue($"{playerKey}|{teamKey}", out webPath!))
        {
            return true;
        }

        return PhotoByUniqueName.TryGetValue(playerKey, out webPath!);
    }

    private static string NormalizeKey(string? value)
    {
        if (string.IsNullOrWhiteSpace(value))
        {
            return string.Empty;
        }

        var normalized = value.Trim().Normalize(NormalizationForm.FormD);
        var builder = new StringBuilder(normalized.Length);
        foreach (var character in normalized)
        {
            if (CharUnicodeInfo.GetUnicodeCategory(character) == UnicodeCategory.NonSpacingMark)
            {
                continue;
            }

            if (char.IsLetterOrDigit(character))
            {
                builder.Append(char.ToUpperInvariant(character));
            }
        }

        return builder.ToString();
    }
}
